function sanitizeCalendarTitle(text) {
  let title = String(text || '')
    .replace(/[?.!]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  title = title
    .replace(/\s+(?:from|off|on|to|in|onto|into)\s+(?:my|your|the)?\s*(?:google\s+)?(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\b.*$/i, '')
    .replace(/\s+(?:to|on|in|onto|into)\s+(?:my|your|the)?\s*(?:google\s+)?(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\b(?:\s+(?:please|pls))?\s*$/i, '')
    .replace(/\s+(?:to|on|in|onto|into)\s+(?:my|your|the)?\s*(?:google\s+)?(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\b/ig, ' ')
    .replace(/\b(?:my|your|the)\s+(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\b\s*$/i, '')
    .replace(/\b(?:calendar|calender|calandar|calander|caliender|gcal)\s+(?:event|entry)\b/ig, ' ')
    .replace(/\s+/g, ' ')
    .trim();
