}
function ymd(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + d;
}
function parseDatePhrase(text) {
  const t = String(text || '').toLowerCase();
  const d = new Date();
  if (/\btoday\b|\btonight\b/.test(t)) return ymd(d);
  if (/\btomorrow\b/.test(t)) { d.setDate(d.getDate() + 1); return ymd(d); }
  const iso = t.match(/\b(20\d{2})-(\d{1,2})-(\d{1,2})\b/);
  if (iso) return iso[1] + '-' + iso[2].padStart(2, '0') + '-' + iso[3].padStart(2, '0');
  const md = t.match(/\b(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?\b/);
  if (md) {
    const year = md[3] ? (md[3].length === 2 ? '20' + md[3] : md[3]) : String(d.getFullYear());
    return year + '-' + md[1].padStart(2, '0') + '-' + md[2].padStart(2, '0');
  }
  const weekdays = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  const idx = weekdays.findIndex(day => new RegExp('\\b' + day + '\\b').test(t));
  if (idx >= 0) {
    let delta = (idx - d.getDay() + 7) % 7;
    if (delta === 0 || /\bnext\b/.test(t)) delta += 7;
    d.setDate(d.getDate() + delta);
    return ymd(d);
  }
  return null;
}
function parseTimePhrase(text) {
  const t = String(text || '').toLowerCase();
  if (/\bnoon\b/.test(t)) return '12:00';
  if (/\bmidnight\b/.test(t)) return '00:00';
  const explicit = t.match(/\b(?:at\s*)?(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b/);
  let m = explicit;
  let meridian = explicit ? explicit[3] : '';
  if (!m) {
    const eveningContext = /\b(tonight|this evening|evening|after dinner|night)\b/.test(t);
    m = t.match(/\bat\s*(\d{1,2})(?::(\d{2}))?\b/) || (eveningContext ? t.match(/\b(\d{1,2}):(\d{2})\b/) : null);
    if (!m) return null;
    meridian = eveningContext ? 'pm' : '';
  }
  let h = Number(m[1]);
  const min = m[2] || '00';
  if (h > 23 || Number(min) > 59) return null;
  if (meridian === 'pm' && h < 12) h += 12;
  if (meridian === 'am' && h === 12) h = 0;
  return String(h).padStart(2, '0') + ':' + min.padStart(2, '0');
}
