    .replace(/^(?:remind me(?: to)?|set a reminder(?: to)?|make a reminder(?: to)?|alert me(?: to)?|remember to|give me a heads up(?: to)?)\s+/i, '')
    .replace(/\s+(?:to|on|in)\s+(?:my\s+)?(?:calendar|cal|gcal|google calendar)\b/i, '')
    .replace(/\b(?:today|tonight|tomorrow|next\s+)?(?:sunday|monday|tuesday|wednesday|thursday|friday|saturday)\b/ig, '')
    .replace(/\b(?:today|tonight|tomorrow)\b/ig, '')
    .replace(/\b20\d{2}-\d{1,2}-\d{1,2}\b/g, '')
    .replace(/\b\d{1,2}\/\d{1,2}(?:\/\d{2,4})?\b/g, '')
    .replace(/\b(?:at\s*)?\d{1,2}(?::\d{2})?\s*(?:am|pm)\b/ig, '')
    .replace(/\b(?:at\s*)?\d{1,2}:\d{2}\b/ig, '')
    .replace(/\bat\s*\d{1,2}\b/ig, '')
    .replace(/\b(noon|midnight)\b/ig, '')
    .replace(/\b(calendar|cal|gcal|google calendar)\b/ig, '')
    .replace(/\s+/g, ' ')
