// Deterministic fallback for common Hue commands if the model forgets an action block.
function inferHueAction(text) {
  const t = String(text || '').toLowerCase();
  const mentionsHue = /(hue|light|lights|lighting|lamp|lamps)\b/.test(t);
  if (!mentionsHue) return null;
  if (/\bhue\b.*\b(off|out)\b/.test(t) || /\b(off|out)\b.*\bhue\b/.test(t)) return { type: 'hue', mode: 'off' };
  if (/\b(cut|kill|shut)\b.*\b(lights?|lamps?)\b/.test(t)) return { type: 'hue', mode: 'off' };
  if (/\bhue\b.*\bon\b/.test(t) || /\bon\b.*\bhue\b/.test(t)) return { type: 'hue', mode: 'on' };
  if (/\b(turn|switch|shut|kill|cut|set)\b.*\b(off|out)\b/.test(t) || /\b(lights?|lamps?)\b.*\b(off|out)\b/.test(t)) return { type: 'hue', mode: 'off' };
  if (/\b(turn|switch|set)\b.*\bon\b/.test(t) || /\b(lights?|lamps?)\b.*\bon\b/.test(t)) return { type: 'hue', mode: 'on' };
  if (/\b(party|disco|dance|rainbow|color\s*loop|colour\s*loop)\b/.test(t)) return { type: 'hue', mode: 'party' };
  if (/\b(relax|cozy|cosy|warm)\b/.test(t)) return { type: 'hue', mode: 'relax' };
  if (/\b(focus|work|concentrat|study)\b/.test(t)) return { type: 'hue', mode: 'focus' };
  if (/\b(night|sleep|bedtime)\b/.test(t)) return { type: 'hue', mode: 'night' };
  if (/\b(dim|dimmer|low|soft)\b/.test(t)) return { type: 'hue', mode: 'dim' };
  if (/\b(bright|brighter|full|alert)\b/.test(t)) return { type: 'hue', mode: 'bright' };
  return null;
}

function inferCalendarDeleteAction(text) {
  const raw = cleanActionText(text);
  const t = raw.toLowerCase();
  if (!/^(?:(?:please|can you|could you)\s+)*(?:delete|remove|cancel)\b/.test(t)) return null;
  if (!/\b(calendar|schedule|event|meeting|appointment)\b/.test(t)) return null;
  let title = '';
  const quoted = raw.match(/["']([^"']+)["']/);
  if (quoted && quoted[1]) title = quoted[1].trim();
  if (!title) {
    const m = raw.match(/\b(?:delete|remove|cancel)\b\s+(?:the\s+)?(?:calendar\s+)?(?:event\s+|meeting\s+|appointment\s+)?(.+?)(?:\s+(?:from|off|on)\s+(?:my\s+)?(?:calendar|schedule))?$/i);
    if (m && m[1]) title = m[1].trim();
  }
  title = title
    .replace(/\s+(?:from|off|on|to|in)\s+(?:my|your|the)?\s*(?:google\s+)?(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\b.*$/i, '')
    .replace(/^(?:my\s+)?(?:calendar|calender|calandar|calander|caliender|cal|gcal|schedule)\s+/i, '')
    .replace(/[?.!]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim();
